// Number of species the NN was trained on.
// CodeJeNN will regenerate this value.
const int n_species_mu = 9;

// Species name table (must match the order in thermophysicalProperties).
// CodeJeNN will regenerate this list.
static constexpr std::array<const char*, n_species_mu> species_names_mu_gen()
{
    return {"H", "H2", "O", "O2", "OH", "H2O", "HO2", "H2O2", "AR"};
}

static std::string species_name_mu_gen(int index)
{
    constexpr auto names = species_names_mu_gen();
    return names[index];
}

// ----------------------------------------------------------
// Activation functions — CodeJeNN will regenerate these.
// ----------------------------------------------------------
template<typename Scalar>
void relu_mu(Scalar* outputs, const Scalar* inputs, size_t size) noexcept
{
    for (size_t i = 0; i < size; ++i)
        outputs[i] = inputs[i] > Scalar(0) ? inputs[i] : Scalar(0);
}

template<typename Scalar>
void linear_mu(Scalar* outputs, const Scalar* inputs, size_t size) noexcept
{
    for (size_t i = 0; i < size; ++i)
        outputs[i] = inputs[i];
}

// ----------------------------------------------------------
// predict_mu
//
// Input layout  (size = n_species_mu + 1):
//   [0]      T          (K)
//   [1..n]   Y_i        (mass fractions, i = 0..n_species_mu-1)
//
// Output (size = n_species_mu):
//   Mu_i  (Pa·s, per-species dynamic viscosity)
//
// STUB: replace everything below with the CodeJeNN-generated
//       network (weight arrays + forward-pass calls).
// ----------------------------------------------------------
inline std::array<scalar, n_species_mu>
predict_mu(const std::array<scalar, n_species_mu + 1>& input)
{
    std::array<scalar, n_species_mu> output;
    for (int i = 0; i < n_species_mu; ++i)
        output[i] = scalar(1e-5);   // placeholder: 1e-5 Pa·s
    return output;
}
